create table marchandises  (id int primary key, reference varchar(50), designation varchar(50) NOT NULL, nom_departement_produit varchar(50) NOT NULL, categorie varchar(50) NOT NULL, prix_dachat_precedent double, prix_vente_precedent double, prix_vente_en_gros_precedent double, description_produit varchar(120), stock_dalerte double, stock_minimum double, stock_maximum double, nom_entreprise_client varchar(50), unite_de_mesure_de_Vente int(3), is_service boolean NOT NULL);
